import { useEffect, useState } from "react";

import axios from "axios";

function ManageCars() {

    const [cars, setCars] =
        useState([]);

    const [variants, setVariants] =
        useState([]);

    const [registrationNumber,
        setRegistrationNumber] =
            useState("");

    const [color,
        setColor] =
            useState("");

    const [variantId,
        setVariantId] =
            useState("");

    useEffect(() => {

        fetchCars();

        fetchVariants();

    }, []);

    const fetchCars = () => {

        axios
            .get(
                "http://localhost:8081/car/all"
            )

            .then((response) => {

                setCars(
                    response.data
                );
            });
    };

    const fetchVariants = () => {

        axios
            .get(
                "http://localhost:8081/variant/all"
            )

            .then((response) => {

                setVariants(
                    response.data
                );
            });
    };

    const addCar = () => {

        const carData = {

            registrationNumber,

            color,

            carVariant: {

                id: variantId
            }
        };

        axios
            .post(
                "http://localhost:8081/car/add",
                carData
            )

            .then(() => {

                alert(
                    "Car Added Successfully"
                );

                setRegistrationNumber("");

                setColor("");

                setVariantId("");

                fetchCars();
            });
    };

    const deleteCar = (id) => {

        axios
            .delete(
                `http://localhost:8081/car/delete/${id}`
            )

            .then(() => {

                alert(
                    "Car Deleted"
                );

                fetchCars();
            });
    };

    const toggleAvailability =
        (id) => {

        axios
            .put(
                `http://localhost:8081/car/availability/${id}`
            )

            .then(() => {

                fetchCars();
            });
    };

    return (

        <div
            style={{
                padding: "30px"
            }}
        >

            <h1>

                Manage Cars

            </h1>

            <br />

            <input
                type="text"

                placeholder=
                    "Registration Number"

                value={
                    registrationNumber
                }

                onChange={(e) =>
                    setRegistrationNumber(
                        e.target.value
                    )
                }
            />

            <br />
            <br />

            <input
                type="text"

                placeholder="Color"

                value={color}

                onChange={(e) =>
                    setColor(
                        e.target.value
                    )
                }
            />

            <br />
            <br />

            <select

                value={variantId}

                onChange={(e) =>
                    setVariantId(
                        e.target.value
                    )
                }
            >

                <option value="">

                    Select Variant

                </option>

                {
                    variants.map(
                        (variant) => (

                        <option
                            key={variant.id}

                            value={
                                variant.id
                            }
                        >

                            {
                                variant.variantName
                            }

                        </option>
                    ))
                }

            </select>

            <br />
            <br />

            <button
                onClick={addCar}
            >

                Add Car

            </button>

            <hr />

            <h2>

                All Cars

            </h2>

            {
                cars.map((car) => (

                    <div

                        key={car.id}

                        style={{
                            border:
                                "1px solid lightgray",

                            padding:
                                "15px",

                            marginBottom:
                                "15px"
                        }}
                    >

                        <h3>

                            {
                                car.registrationNumber
                            }

                        </h3>

                        <p>

                            Color:
                            {" "}
                            {car.color}

                        </p>

                        <p>

                            Variant:
                            {" "}

                            {
                                car.carVariant
                                ?.variantName
                            }

                        </p>

                        <p>

                            Available:
                            {" "}

                            {
                                car.available
                                    ? "Yes"
                                    : "No"
                            }

                        </p>

                        <button

                            onClick={() =>
                                toggleAvailability(
                                    car.id
                                )
                            }
                        >

                            Toggle Availability

                        </button>

                        <button

                            onClick={() =>
                                deleteCar(
                                    car.id
                                )
                            }

                            style={{
                                marginLeft:
                                    "10px"
                            }}
                        >

                            Delete

                        </button>

                    </div>
                ))
            }

        </div>
    );
}

export default ManageCars;
